import React from 'react';
import { Link } from 'react-router-dom';


function Sidebar() {
  const role = localStorage.getItem('role');

  return (
    <div className="sidebar">
      <h3>📂 QUẢN LÝ LÂM SẢN</h3>
      <ul>
        <li><Link to="/dashboard">🏠 Trang chủ</Link></li>

        {/* Mục Đăng ký và quản lý (sử dụng <details> để xổ xuống) */}
        <li>
          <details>
            <summary>📁 Đăng ký và quản lý</summary> {/* Tiêu đề có thể click */}
            <ul style={{ paddingLeft: '1em' }}> {/* Menu con */}
              <li><Link to="/khai-bao">📝 Khai báo cơ sở nuôi</Link></li>
              <li><Link to="/admin/farms">📋 Quản lý cơ sở nuôi</Link></li>
            </ul>
          </details>
        </li>

        {/* Mục Thống kê và báo cáo (sử dụng <details> để xổ xuống) */}
        <li>
          <details>
            <summary>📊 Thống kê và báo cáo</summary> {/* Tiêu đề có thể click */}
            <ul style={{ paddingLeft: '1em' }}> {/* Menu con */}
              <li><Link to="/dashboard">📈 Thống kê</Link></li> 
              <li><Link to="/dashboard">📄 Báo cáo</Link></li>
            </ul>
          </details>
        </li>

        {/* Các mục chỉ dành cho Admin (không thay đổi cấu trúc này) */}
        {role === 'admin' && (
          <>
            <li><Link to="/admin/users">👤 Quản lý người dùng</Link></li>
            <li><Link to="/admin/customers">🏢 Quản lý khách hàng</Link></li>
          </>
        )}

        <li><Link to="/logout">🚪 Đăng xuất</Link></li>
      </ul>
    </div>
  );
}

export default Sidebar;
